static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MatmulWithTransposedBCustomTilingData tiling;

    // Get input shapes as StorageShape, then access origin shape
    const gert::StorageShape *a_storage = context->GetInputShape(0);
    const gert::StorageShape *b_storage = context->GetInputShape(1);
    const gert::Shape &a_shape = a_storage->GetOriginShape();
    const gert::Shape &b_shape = b_storage->GetOriginShape();

    uint32_t M = a_shape.GetDim(0);
    uint32_t K = a_shape.GetDim(1);
    // B is (N, K) but we will transpose inside kernel, so N = dim0 of B
    uint32_t N = b_shape.GetDim(0);

    // Default tile sizes for 910B cube
    uint32_t blockM = 128;
    uint32_t blockN = 128;
    uint32_t blockK = 128;

    // Compute blockDim: use number of output tiles, capped to 16
    uint32_t numMBlocks = (M + blockM - 1) / blockM;
    uint32_t numNBlocks = (N + blockN - 1) / blockN;
    uint32_t numTiles = numMBlocks * numNBlocks;
    uint32_t blockDim = (numTiles > 16) ? 16 : (numTiles > 0 ? numTiles : 1);
    if (blockDim < 1) blockDim = 1;
    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_blockM(blockM);
    tiling.set_blockN(blockN);
    tiling.set_blockK(blockK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

